def solution(limit: int = 1000) -> int:
    best_d = 1
    max_len = 0
    for d in range(2, limit):
        remainders = {}
        curr_rem = 1
        pos = 0
        while curr_rem != 0 and curr_rem not in remainders:
            remainders[curr_rem] = pos
            curr_rem = (curr_rem * 10) % d
            pos += 1
        if curr_rem != 0:
            cycle_len = pos - remainders[curr_rem]
            if cycle_len > max_len:
                max_len = cycle_len
                best_d = d
    return best_d
